using System.Collections.Generic;
using Practice.Scripts.Diplomacy.Events;
using Practice.Scripts.Diplomacy.Model;
using Practice.Scripts.Diplomacy.Views;
using Practice.Scripts.Economy;
using Practice.Scripts.Economy.Events;
using Practice.Scripts.Faction;

namespace Practice.Scripts.Diplomacy.Controller;

public class DiplomacyController
{

    private DiplomacyService _diplomacyService;
    private EconomyService _economyService;
    private DiplomacyEvents _diplomacyEvents;

    public DiplomacyController(FactionService factionService, EconomyService economyService, DiplomacyEvents diplomacyEvents, List<Treaty> treaties)
    {
        _economyService = economyService;
        _diplomacyService = new DiplomacyService(factionService, treaties);
        _diplomacyEvents = diplomacyEvents;
    }

    public void SendGift(string fromFactionId, string toFactionId, int amount)
    {
        _economyService.TransactCoins(fromFactionId, toFactionId, amount);
        _diplomacyService.UpdateOpinion(fromFactionId, toFactionId, 25);
        _diplomacyEvents.EmitOpinionChanged(fromFactionId, toFactionId, _diplomacyService.GetOpinionOf(fromFactionId, toFactionId));

    }

    public DiplomacyViewDTO GetDiplomacyViewData(string ownFactionId, string otherFactionId)
    {
        return _diplomacyService.GetDiplomacyViewData(ownFactionId, otherFactionId);
    }


}

using System.Collections.Generic;
using Practice.Scripts.Diplomacy.Events;
using Practice.Scripts.Diplomacy.Model;
using Practice.Scripts.Diplomacy.Model.Enum;
using Practice.Scripts.Diplomacy.Views;
using Practice.Scripts.Economy;
using Practice.Scripts.Faction;

namespace Practice.Scripts.Diplomacy.Controller;

public class DiplomacyController
{
    private const int GiftCost = 50;
    private const int GiftOpinionBoost = 25;

    private DiplomacyService _diplomacyService;
    private EconomyService _economyService;
    private DiplomacyEvents _diplomacyEvents;
    private FactionService _factionService;

    public DiplomacyController(FactionService factionService, EconomyService economyService, DiplomacyEvents diplomacyEvents, List<Treaty> treaties)
    {
        _factionService = factionService;
        _economyService = economyService;
        _diplomacyService = new DiplomacyService(factionService, treaties);
        _diplomacyEvents = diplomacyEvents;
    }

    public DiplomacyViewDTO GetDiplomacyViewData(string ownFactionId, string otherFactionId)
    {
        return _diplomacyService.GetDiplomacyViewData(ownFactionId, otherFactionId);
    }

    // -- Actions --

    public void DeclareWar(string from, string to)
    {
        _diplomacyService.DeclareWar(from, to);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void MakePeace(string from, string to)
    {
        _diplomacyService.MakePeace(from, to);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void SignNonAggression(string from, string to)
    {
        _diplomacyService.CreateTreaty(from, to, TreatyType.NonAggression);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void CancelNonAggression(string from, string to)
    {
        _diplomacyService.CancelTreaty(from, to, TreatyType.NonAggression);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void FormAlliance(string from, string to)
    {
        _diplomacyService.FormAlliance(from, to);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void CancelAlliance(string from, string to)
    {
        _diplomacyService.CancelAlliance(from, to);
        _diplomacyEvents.EmitTreatyChanged(from, to);
    }

    public void SendGift(string from, string to)
    {
        _economyService.TransactCoins(from, to, GiftCost);
        _diplomacyService.UpdateOpinion(to, from, GiftOpinionBoost);
        _diplomacyEvents.EmitOpinionChanged(to, from, _diplomacyService.GetOpinionOf(to, from));
    }

    // -- Queries --

    public bool CanDeclareWar(string a, string b) => _diplomacyService.CanDeclareWar(a, b);

    public bool IsAtWar(string a, string b) => _diplomacyService.HasTreatyType(a, b, TreatyType.War);

    public bool HasNonAggression(string a, string b) => _diplomacyService.HasTreatyType(a, b, TreatyType.NonAggression);

    public bool HasAlliance(string a, string b) => _diplomacyService.HasTreatyType(a, b, TreatyType.Alliance);

    public bool CanAffordGift(string factionId)
    {
        var f = _factionService.GetFaction(factionId);
        return f != null && f.Coins >= GiftCost;
    }

    public int GetGiftCost() => GiftCost;

    public Godot.Texture2D GetFactionCrest(string factionId)
    {
        var f = _factionService.GetFaction(factionId);
        return f?.Crest;
    }
}

using System.Collections.Generic;
using Practice.Scripts.Diplomacy.Model;
using Practice.Scripts.Diplomacy.Model.Enum;
using Practice.Scripts.Diplomacy.Views;
using Practice.Scripts.Faction;

namespace Practice.Scripts.Diplomacy;

public class DiplomacyService
{

    private FactionService _factionService;
    private List<Treaty> _treaties;

    public DiplomacyService(FactionService factionService, List<Treaty> treaties)
    {
        _factionService = factionService;
        _treaties = treaties;
    }

    public int GetOpinionOf(string ownFactionId, string otherFactionId)
    {
        var ownFaction = _factionService.GetFaction(ownFactionId);
        if (ownFaction == null) return 0;
        if (!ownFaction.Opinions.ContainsKey(otherFactionId)) return 0;
        return ownFaction.Opinions[otherFactionId];
    }

    public void CreateTreaty(string factionAId, string factionBId, TreatyType type)
    {
        var existingTreaty = _treaties.Find(t =>
            (t.A == factionAId && t.B == factionBId) ||
            (t.A == factionBId && t.B == factionAId));
        if (existingTreaty != null)
        {
            existingTreaty.Type = type;
        }
        else
        {
            _treaties.Add(new Treaty
            {
                A = factionAId,
                B = factionBId,
                Type = type
            });
        }
    }

    public void CancelTreaty(string factionAId, string factionBId, TreatyType type)
    {
        _treaties.RemoveAll(t =>
            ((t.A == factionAId && t.B == factionBId) ||
             (t.A == factionBId && t.B == factionAId)) &&
            t.Type == type);
    }

    public List<Treaty> GetTreatiesBetween(string factionAId, string factionBId)
    {
        return _treaties.FindAll(t =>
            (t.A == factionAId && t.B == factionBId) ||
            (t.A == factionBId && t.B == factionAId));
    }

    public List<Treaty> GetTreatiesOf(string factionId)
    {
        return _treaties.FindAll(t => t.A == factionId || t.B == factionId);
    }

    public DiplomacyViewDTO GetDiplomacyViewData (string ownFactionId, string otherFactionId)
    {
        var ownFaction = _factionService.GetFaction(ownFactionId);
        var otherFaction = _factionService.GetFaction(otherFactionId);
        if (ownFaction == null || otherFaction == null) return null;
        var mutualOpinion = GetMutualOpinion(ownFactionId, otherFactionId);

        var ownFactionDTO = new DiplomacyViewFactionDTO
        {
            FactionId = ownFaction.Id,
            FactionName = ownFaction.Name,
        };
        var otherFactionDTO = new DiplomacyViewFactionDTO
        {
            FactionId = otherFaction.Id,
            FactionName = otherFaction.Name,
        };

        var treaties = GetTreatiesBetween(ownFactionId, otherFactionId);

        return new DiplomacyViewDTO
        {
            Us = ownFactionDTO,
            Them = otherFactionDTO,
            Opinion = mutualOpinion,
            Relation = GetRelationType(treaties),
            Treaties = treaties
        };
    }

    public void MakePeace(string factionAId, string factionBId)
    {
        CancelTreaty(factionAId, factionBId, TreatyType.War);
    }

    public void DeclareWar(string factionAId, string factionBId)
    {
        if (!CanDeclareWar(factionAId, factionBId))
            return;
        CreateTreaty(factionAId, factionBId, TreatyType.War);
    }

    public bool CanDeclareWar(string factionAId, string factionBId)
    {
        if (HasTreaty(factionAId, factionBId, TreatyType.Alliance))
            return false;
        if (HasTreaty(factionAId, factionBId, TreatyType.War))
            return false;
        if (HasTreaty(factionAId, factionBId, TreatyType.NonAggression))
            return false;
        return true;
    }

    private bool HasTreaty(string factionAId, string factionBId, TreatyType type)
    {
        var treaty = _treaties.Find(t =>
            (t.A == factionAId && t.B == factionBId) ||
            (t.A == factionBId && t.B == factionAId));
        if (treaty != null && treaty.Type == type)
            return true;
        else
            return false;
    }

    public void FormAlliance(string factionAId, string factionBId)
    {
        CreateTreaty(factionAId, factionBId, TreatyType.Alliance);
    }

    public void CancelAlliance(string factionAId, string factionBId)
    {
        CancelTreaty(factionAId, factionBId, TreatyType.Alliance);
    }


    public void UpdateOpinion(string fromFactionId, string toFactionId, int amount)
    {
        var fromFaction = _factionService.GetFaction(fromFactionId);
        if (fromFaction == null) return;

        if (!fromFaction.Opinions.ContainsKey(toFactionId))
            fromFaction.Opinions[toFactionId] = 0;

        if (amount < -100)
            amount = -100;
        if (amount > 100)
            amount = 100;

        fromFaction.Opinions[toFactionId] += amount;

    }



    public RelationType GetRelationType(List<Treaty> treaties)
    {
        var allianceExists = treaties.Exists(t => t.Type == TreatyType.Alliance);
        var warExists = treaties.Exists(t => t.Type == TreatyType.War);

        if (allianceExists)
            return RelationType.Ally;
        if (warExists)
            return RelationType.Enemy;
        else
            return RelationType.Neutral;
    }

    public MutualOpinionDto GetMutualOpinion(string a, string b)
    {
        return new MutualOpinionDto
        {
            FromAToB = GetOpinionOf(a, b),
            FromBToA = GetOpinionOf(b, a)
        };
    }

}

public class MutualOpinionDto
{
    public int FromAToB;
    public int FromBToA;
}

